@page "/"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1 class="mb-4">Dashboard</h1>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="row g-4">
        <div class="col-md-4">
            <div class="card border-primary h-100">
                <div class="card-body text-center">
                    <h5 class="card-title text-primary">Today's Appointments</h5>
                    <p class="display-4 fw-bold">@todaysAppointments</p>
                    <a href="/appointments" class="btn btn-outline-primary btn-sm">View Schedule</a>
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card border-success h-100">
                <div class="card-body text-center">
                    <h5 class="card-title text-success">Total Patients</h5>
                    <p class="display-4 fw-bold">@totalPatients</p>
                    <a href="/patients" class="btn btn-outline-success btn-sm">View Patients</a>
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card border-warning h-100">
                <div class="card-body text-center">
                    <h5 class="card-title text-warning">Pending Invoices</h5>
                    <p class="display-4 fw-bold">@pendingInvoices</p>
                    <a href="/billing" class="btn btn-outline-warning btn-sm">View Billing</a>
                </div>
            </div>
        </div>
    </div>

    <div class="row mt-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Today's Schedule</h5>
                </div>
                <div class="card-body">
                    @if (todaysAppointmentList.Any())
                    {
                        <table class="table table-hover">
                            <thead>
                                <tr>
                                    <th>Time</th>
                                    <th>Pet</th>
                                    <th>Owner</th>
                                    <th>Reason</th>
                                    <th>Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var appt in todaysAppointmentList)
                                {
                                    <tr>
                                        <td>@appt.StartTime.ToString("HH:mm") - @appt.EndTime.ToString("HH:mm")</td>
                                        <td>@appt.Pet.Name</td>
                                        <td>@appt.Pet.Owner.FullName</td>
                                        <td>@appt.Reason</td>
                                        <td>
                                            <span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span>
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                    else
                    {
                        <p class="text-muted mb-0">No appointments scheduled for today.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool isLoading = true;
    private int todaysAppointments;
    private int totalPatients;
    private int pendingInvoices;
    private List<Appointment> todaysAppointmentList = [];

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);

        todaysAppointmentList = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        todaysAppointments = todaysAppointmentList.Count;
        totalPatients = await Db.Pets.CountAsync();
        pendingInvoices = await Db.Invoices.CountAsync(i => !i.IsPaid);

        isLoading = false;
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patients - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Patients</h1>
    <button class="btn btn-primary" @onclick="ToggleAddForm">
        <i class="bi bi-plus-lg"></i> @(showAddForm ? "Cancel" : "Add Patient")
    </button>
</div>

@if (showAddForm)
{
    <div class="card mb-4">
        <div class="card-header bg-primary text-white">
            <h5 class="mb-0">Register New Patient</h5>
        </div>
        <div class="card-body">
            <EditForm Model="newPet" OnValidSubmit="AddPatient" FormName="addPatient">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Pet Name</label>
                        <InputText @bind-Value="newPet.Name" class="form-control" />
                        <ValidationMessage For="() => newPet.Name" class="text-danger" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Species</label>
                        <InputText @bind-Value="newPet.Species" class="form-control" />
                        <ValidationMessage For="() => newPet.Species" class="text-danger" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Breed</label>
                        <InputText @bind-Value="newPet.Breed" class="form-control" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Date of Birth</label>
                        <InputDate @bind-Value="newPet.DateOfBirth" class="form-control" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber @bind-Value="newPet.WeightKg" class="form-control" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Owner</label>
                        @if (createNewOwner)
                        {
                            <div class="input-group">
                                <InputText @bind-Value="newOwnerFirst" class="form-control" placeholder="First Name" />
                                <InputText @bind-Value="newOwnerLast" class="form-control" placeholder="Last Name" />
                                <button type="button" class="btn btn-outline-secondary" @onclick="() => createNewOwner = false">
                                    Select Existing
                                </button>
                            </div>
                            <div class="row mt-2">
                                <div class="col-6">
                                    <InputText @bind-Value="newOwnerPhone" class="form-control" placeholder="Phone" />
                                </div>
                                <div class="col-6">
                                    <InputText @bind-Value="newOwnerEmail" class="form-control" placeholder="Email" />
                                </div>
                            </div>
                        }
                        else
                        {
                            <div class="input-group">
                                <InputSelect @bind-Value="newPet.OwnerId" class="form-select">
                                    <option value="0">-- Select Owner --</option>
                                    @foreach (var owner in owners)
                                    {
                                        <option value="@owner.Id">@owner.FullName</option>
                                    }
                                </InputSelect>
                                <button type="button" class="btn btn-outline-secondary" @onclick="() => createNewOwner = true">
                                    New Owner
                                </button>
                            </div>
                        }
                    </div>
                </div>

                <div class="mt-3">
                    <button type="submit" class="btn btn-success" disabled="@isSaving">
                        @if (isSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save Patient
                    </button>
                </div>
            </EditForm>
        </div>
    </div>
}

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search patients by name, species, breed, or owner..."
           @oninput="OnSearchChanged" value="@searchTerm" />
</div>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (!filteredPets.Any())
{
    <div class="alert alert-info">No patients found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                    <th>Age</th>
                    <th>Weight</th>
                    <th>Owner</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pet in filteredPets)
                {
                    <tr>
                        <td><strong>@pet.Name</strong></td>
                        <td>@pet.Species</td>
                        <td>@(pet.Breed ?? "—")</td>
                        <td>@GetAge(pet.DateOfBirth)</td>
                        <td>@(pet.WeightKg.HasValue ? $"{pet.WeightKg:F1} kg" : "—")</td>
                        <td>@pet.Owner.FullName</td>
                        <td>
                            <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">Edit</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private bool isLoading = true;
    private bool showAddForm;
    private bool createNewOwner;
    private bool isSaving;
    private string searchTerm = string.Empty;
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private Pet newPet = new();
    private string newOwnerFirst = string.Empty;
    private string newOwnerLast = string.Empty;
    private string newOwnerPhone = string.Empty;
    private string newOwnerEmail = string.Empty;

    private IEnumerable<Pet> filteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            (p.Breed?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
            p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        isLoading = false;
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ToggleAddForm()
    {
        showAddForm = !showAddForm;
        if (showAddForm)
        {
            newPet = new Pet();
            createNewOwner = false;
            newOwnerFirst = string.Empty;
            newOwnerLast = string.Empty;
            newOwnerPhone = string.Empty;
            newOwnerEmail = string.Empty;
        }
    }

    private async Task AddPatient()
    {
        isSaving = true;
        try
        {
            if (createNewOwner)
            {
                if (string.IsNullOrWhiteSpace(newOwnerFirst) || string.IsNullOrWhiteSpace(newOwnerLast))
                    return;

                var owner = new Owner
                {
                    FirstName = newOwnerFirst.Trim(),
                    LastName = newOwnerLast.Trim(),
                    Phone = string.IsNullOrWhiteSpace(newOwnerPhone) ? null : newOwnerPhone.Trim(),
                    Email = string.IsNullOrWhiteSpace(newOwnerEmail) ? null : newOwnerEmail.Trim()
                };
                Db.Owners.Add(owner);
                await Db.SaveChangesAsync();
                newPet.OwnerId = owner.Id;
            }

            if (newPet.OwnerId == 0) return;

            Db.Pets.Add(newPet);
            await Db.SaveChangesAsync();

            showAddForm = false;
            await LoadData();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void OnSearchChanged(ChangeEventArgs e)
    {
        searchTerm = e.Value?.ToString() ?? string.Empty;
    }

    private string GetAge(DateOnly? dob)
    {
        if (!dob.HasValue) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dob.Value.Year;
        if (dob.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

