@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private List<Owner> owners = [];
    private Treatment newTreatment = new();
    private DateOnly treatmentDate = DateOnly.FromDateTime(DateTime.Today);
    private bool isLoading = true;
    private bool isEditing;
    private bool isSaving;

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        isLoading = false;
    }

    private async Task LoadPet()
    {
        pet = await Db.Pets
            .Include(p => p.Owner)
            .Include(p => p.Treatments)
            .FirstOrDefaultAsync(p => p.Id == Id);
    }

    private async Task SavePet()
    {
        if (pet is null) return;
        isSaving = true;
        try
        {
            await Db.SaveChangesAsync();
            isEditing = false;
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task AddTreatment()
    {
        if (pet is null) return;
        isSaving = true;
        try
        {
            newTreatment.PetId = pet.Id;
            newTreatment.Date = treatmentDate.ToDateTime(TimeOnly.MinValue);
            Db.Treatments.Add(newTreatment);
            await Db.SaveChangesAsync();

            pet.Treatments.Add(newTreatment);
            newTreatment = new Treatment();
            treatmentDate = DateOnly.FromDateTime(DateTime.Today);
        }
        finally
        {
            isSaving = false;
        }
    }
}

