@code {
    private bool isLoading = true;
    private bool showAddForm;
    private bool createNewOwner;
    private bool isSaving;
    private string searchTerm = string.Empty;
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private Pet newPet = new();
    private string newOwnerFirst = string.Empty;
    private string newOwnerLast = string.Empty;
    private string newOwnerPhone = string.Empty;
    private string newOwnerEmail = string.Empty;

    private IEnumerable<Pet> filteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            (p.Breed?.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ?? false) ||
            p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        isLoading = false;
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ToggleAddForm()
    {
        showAddForm = !showAddForm;
        if (showAddForm)
        {
            newPet = new Pet();
            createNewOwner = false;
            newOwnerFirst = string.Empty;
            newOwnerLast = string.Empty;
            newOwnerPhone = string.Empty;
            newOwnerEmail = string.Empty;
        }
    }

    private async Task AddPatient()
    {
        isSaving = true;
        try
        {
            if (createNewOwner)
            {
                if (string.IsNullOrWhiteSpace(newOwnerFirst) || string.IsNullOrWhiteSpace(newOwnerLast))
                    return;

                var owner = new Owner
                {
                    FirstName = newOwnerFirst.Trim(),
                    LastName = newOwnerLast.Trim(),
                    Phone = string.IsNullOrWhiteSpace(newOwnerPhone) ? null : newOwnerPhone.Trim(),
                    Email = string.IsNullOrWhiteSpace(newOwnerEmail) ? null : newOwnerEmail.Trim()
                };
                Db.Owners.Add(owner);
                await Db.SaveChangesAsync();
                newPet.OwnerId = owner.Id;
            }

            if (newPet.OwnerId == 0) return;

            Db.Pets.Add(newPet);
            await Db.SaveChangesAsync();

            showAddForm = false;
            await LoadData();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void OnSearchChanged(ChangeEventArgs e)
    {
        searchTerm = e.Value?.ToString() ?? string.Empty;
    }

    private string GetAge(DateOnly? dob)
    {
        if (!dob.HasValue) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dob.Value.Year;
        if (dob.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

