@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered table-sm" style="font-size: 0.8rem;">
            <thead class="table-dark">
                <tr>
                    <th style="width:60px;">Time</th>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        <th class="text-center">@day.ToString("ddd MM/dd")</th>
                    }
                </tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    <tr>
                        <td class="fw-bold text-nowrap">@slot</td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            var slotTime = day.Add(TimeSpan.Parse(slot));
                            var appt = GetAppointmentAt(slotTime);
                            if (appt is not null)
                            {
                                var color = appt.Status == AppointmentStatus.Completed ? "bg-success" :
                                            appt.Status == AppointmentStatus.Cancelled ? "bg-secondary" : "bg-primary";
                                <td class="@color text-white p-1 cursor-pointer" @onclick="() => EditAppointment(appt)"
                                    title="@appt.Pet.Name - @appt.Reason">
                                    @appt.Pet.Name
                                </td>
                            }
                            else
                            {
                                var isOccupied = IsSlotOccupied(slotTime);
                                <td class="@(isOccupied ? "bg-warning-subtle" : "")"></td>
                            }
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <div class="mt-3">
        <span class="badge bg-primary me-2">Scheduled</span>
        <span class="badge bg-success me-2">Completed</span>
        <span class="badge bg-secondary me-2">Cancelled</span>
        <span class="badge bg-warning-subtle text-dark me-2">Occupied</span>
    </div>
}

@code {
    private bool isLoading = true;
    private bool showNewForm;
    private bool isSaving;
    private DateTime weekStart;
    private List<Appointment> weekAppointments = [];
    private List<Pet> allPets = [];
    private Appointment formModel = new();
    private Appointment? editingAppointment;
    private Pet? selectedPet;
    private string petSearchTerm = string.Empty;
    private List<Pet> petSearchResults = [];
    private DateOnly formDate = DateOnly.FromDateTime(DateTime.Today);
    private string formStartTime = "09:00";
    private string formEndTime = "09:30";

    private static readonly List<string> timeSlots = Enumerable.Range(16, 20) // 8:00 to 17:30 (half hours)
        .Select(i => TimeSpan.FromMinutes(i * 30).ToString(@"hh\:mm"))
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        weekStart = GetMonday(DateTime.Today);
        allPets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadWeekAppointments();
        isLoading = false;
    }

    private async Task LoadWeekAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
            .ToListAsync();
    }

    private static DateTime GetMonday(DateTime date)
    {
        var diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        return date.AddDays(-diff).Date;
    }

    private async Task PreviousWeek() { weekStart = weekStart.AddDays(-7); await LoadWeekAppointments(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadWeekAppointments(); }

    private void ToggleNewForm()
    {
        showNewForm = !showNewForm;
        editingAppointment = null;
        formModel = new Appointment();
        selectedPet = null;
        petSearchTerm = string.Empty;
        petSearchResults = [];
        formDate = DateOnly.FromDateTime(DateTime.Today);
        formStartTime = "09:00";
        formEndTime = "09:30";
    }

    private void OnPetSearch(ChangeEventArgs e)
    {
        petSearchTerm = e.Value?.ToString() ?? string.Empty;
        if (string.IsNullOrWhiteSpace(petSearchTerm))
        {
            petSearchResults = [];
            return;
        }
        petSearchResults = allPets
            .Where(p => p.Name.Contains(petSearchTerm, StringComparison.OrdinalIgnoreCase) ||
                        p.Owner.FullName.Contains(petSearchTerm, StringComparison.OrdinalIgnoreCase))
            .Take(10).ToList();
    }

    private void SelectPet(Pet p)
    {
        selectedPet = p;
        petSearchTerm = p.Name;
        petSearchResults = [];
    }

    private void EditAppointment(Appointment appt)
    {
        editingAppointment = appt;
        formModel = appt;
        selectedPet = appt.Pet;
        petSearchTerm = appt.Pet.Name;
        formDate = DateOnly.FromDateTime(appt.StartTime);
        formStartTime = appt.StartTime.ToString("HH:mm");
        formEndTime = appt.EndTime.ToString("HH:mm");
        showNewForm = true;
    }

    private async Task SaveAppointment()
    {
        if (selectedPet is null) return;
        isSaving = true;
        try
        {
            var startDateTime = formDate.ToDateTime(TimeOnly.Parse(formStartTime));
            var endDateTime = formDate.ToDateTime(TimeOnly.Parse(formEndTime));

            if (editingAppointment is not null)
            {
                editingAppointment.PetId = selectedPet.Id;
                editingAppointment.StartTime = startDateTime;
                editingAppointment.EndTime = endDateTime;
                editingAppointment.Reason = formModel.Reason;
                editingAppointment.Notes = formModel.Notes;
            }
            else
            {
                var appt = new Appointment
                {
                    PetId = selectedPet.Id,
                    StartTime = startDateTime,
                    EndTime = endDateTime,
                    Reason = formModel.Reason,
                    Notes = formModel.Notes,
                    Status = AppointmentStatus.Scheduled
                };
                Db.Appointments.Add(appt);
            }

            await Db.SaveChangesAsync();
            showNewForm = false;
            editingAppointment = null;
            await LoadWeekAppointments();
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task CancelAppointment()
    {
        if (editingAppointment is null) return;
        isSaving = true;
        try
        {
            editingAppointment.Status = AppointmentStatus.Cancelled;
            await Db.SaveChangesAsync();
            showNewForm = false;
            editingAppointment = null;
            await LoadWeekAppointments();
        }
        finally
        {
            isSaving = false;
        }
    }

    private Appointment? GetAppointmentAt(DateTime slotTime)
    {
        return weekAppointments.FirstOrDefault(a =>
            a.StartTime == slotTime && a.Status != AppointmentStatus.Cancelled);
    }

    private bool IsSlotOccupied(DateTime slotTime)
    {
        return weekAppointments.Any(a =>
            a.Status != AppointmentStatus.Cancelled &&
            slotTime >= a.StartTime && slotTime < a.EndTime && a.StartTime != slotTime);
    }
}

@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Billing - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Billing</h1>
    <button class="btn btn-primary" @onclick="ToggleNewInvoice">
        @(showNewInvoice ? "Cancel" : "New Invoice")
    </button>
</div>

@if (showNewInvoice)
{
    <div class="card mb-4">
        <div class="card-header bg-primary text-white">
            <h5 class="mb-0">Create Invoice</h5>
        </div>
        <div class="card-body">
            <EditForm Model="newInvoice" OnValidSubmit="CreateInvoice" FormName="createInvoice">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="row g-3 mb-3">
                    <div class="col-md-4">
                        <label class="form-label">Owner</label>
                        <InputSelect @bind-Value="newInvoice.OwnerId" class="form-select">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-8">
                        <label class="form-label">Description</label>
                        <InputText @bind-Value="newInvoice.Description" class="form-control" />
                    </div>
                </div>

                <h6>Line Items</h6>
                <table class="table table-sm">
                    <thead>
                        <tr>
                            <th>Description</th>
                            <th style="width:150px;">Amount</th>
                            <th style="width:80px;"></th>
                        </tr>
                    </thead>
                    <tbody>
                        @for (int i = 0; i < lineItems.Count; i++)
                        {
                            var idx = i;
                            <tr>
                                <td>
                                    <input type="text" class="form-control form-control-sm"
                                           @bind="lineItems[idx].Description" @bind:event="oninput" />
                                </td>
                                <td>
                                    <input type="number" step="0.01" class="form-control form-control-sm"
                                           @bind="lineItems[idx].Amount" @bind:event="oninput" />
                                </td>
                                <td>
                                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => lineItems.RemoveAt(idx)">
                                        &times;
                                    </button>
                                </td>
                            </tr>
                        }
                    </tbody>
                    <tfoot>
                        <tr>
                            <td>
                                <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="AddLineItem">
                                    + Add Line Item
                                </button>
                            </td>
                            <td class="fw-bold text-end">Total: @lineItems.Sum(l => l.Amount).ToString("C")</td>
                            <td></td>
                        </tr>
                    </tfoot>
                </table>

                <button type="submit" class="btn btn-success" disabled="@isSaving">
                    @if (isSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Create Invoice
                </button>
            </EditForm>
        </div>
    </div>
}

@if (showPaymentForm)
{
    <div class="card mb-4 border-success">
        <div class="card-header bg-success text-white">
            <h5 class="mb-0">Record Payment — Invoice #@payingInvoice!.Id</h5>
        </div>
        <div class="card-body">
            <EditForm Model="newPayment" OnValidSubmit="RecordPayment" FormName="recordPayment">
                <DataAnnotationsValidator />

                <div class="row g-3">
                    <div class="col-md-3">
                        <label class="form-label">Amount</label>
                        <InputNumber @bind-Value="newPayment.Amount" class="form-control" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <InputSelect @bind-Value="newPayment.Method" class="form-select">
                            <option value="Cash">Cash</option>
                            <option value="Card">Card</option>
                            <option value="Check">Check</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <InputText @bind-Value="newPayment.Reference" class="form-control" />
                    </div>
                    <div class="col-md-3 d-flex align-items-end gap-2">
                        <button type="submit" class="btn btn-success" disabled="@isSaving">
                            @if (isSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Pay
                        </button>
                        <button type="button" class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Invoices</h5>
        </div>
        <div class="card-body p-0">
            @if (invoices.Any())
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>#</th>
                                <th>Date</th>
                                <th>Owner</th>
                                <th>Description</th>
                                <th>Amount</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var inv in invoices)
                            {
                                <tr>
                                    <td>@inv.Id</td>
                                    <td>@inv.CreatedDate.ToString("yyyy-MM-dd")</td>
                                    <td>@inv.Owner.FullName</td>
                                    <td>@(inv.Description ?? "—")</td>
                                    <td>@inv.TotalAmount.ToString("C")</td>
                                    <td>
                                        @if (inv.IsPaid)
                                        {
                                            <span class="badge bg-success">Paid</span>
                                        }
                                        else
                                        {
                                            <span class="badge bg-warning text-dark">Unpaid</span>
                                        }
                                    </td>
                                    <td>
                                        @if (!inv.IsPaid)
                                        {
                                            <button class="btn btn-sm btn-outline-success" @onclick="() => OpenPayment(inv)">
                                                Pay
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted p-3 mb-0">No invoices found.</p>
            }
        </div>
    </div>

    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Payment History</h5>
        </div>
        <div class="card-body p-0">
            @if (payments.Any())
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Date</th>
                                <th>Invoice #</th>
                                <th>Owner</th>
                                <th>Amount</th>
                                <th>Method</th>
                                <th>Reference</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var pay in payments)
                            {
                                <tr>
                                    <td>@pay.PaymentDate.ToString("yyyy-MM-dd")</td>
                                    <td>@pay.InvoiceId</td>
                                    <td>@pay.Invoice.Owner.FullName</td>
                                    <td>@pay.Amount.ToString("C")</td>
                                    <td>@pay.Method</td>
                                    <td>@(pay.Reference ?? "—")</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted p-3 mb-0">No payments recorded.</p>
            }
        </div>
    </div>
}

@code {
    private bool isLoading = true;
    private bool showNewInvoice;
    private bool showPaymentForm;
    private bool isSaving;

    private List<Invoice> invoices = [];
    private List<Payment> payments = [];
    private List<Owner> owners = [];
    private Invoice newInvoice = new();
    private List<InvoiceLineItem> lineItems = [new()];
    private Payment newPayment = new();
    private Invoice? payingInvoice;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        isLoading = false;
    }

    private async Task LoadData()
    {
        invoices = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();

        payments = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();

        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ToggleNewInvoice()
    {
        showNewInvoice = !showNewInvoice;
        if (showNewInvoice)
        {
            newInvoice = new Invoice();
            lineItems = [new InvoiceLineItem()];
        }
    }

    private void AddLineItem()
    {
        lineItems.Add(new InvoiceLineItem());
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.OwnerId == 0) return;
        isSaving = true;
        try
        {
            var validItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description)).ToList();
            newInvoice.TotalAmount = validItems.Sum(l => l.Amount);
            newInvoice.CreatedDate = DateTime.UtcNow;

            Db.Invoices.Add(newInvoice);
            await Db.SaveChangesAsync();

            foreach (var item in validItems)
            {
                item.InvoiceId = newInvoice.Id;
                Db.InvoiceLineItems.Add(item);
            }
            await Db.SaveChangesAsync();

            showNewInvoice = false;
            await LoadData();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void OpenPayment(Invoice invoice)
    {
        payingInvoice = invoice;
        var remaining = invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount);
        newPayment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = remaining,
            Method = "Cash"
        };
        showPaymentForm = true;
    }

    private async Task RecordPayment()
    {
        if (payingInvoice is null) return;
        isSaving = true;
        try
        {
            newPayment.PaymentDate = DateTime.UtcNow;
            Db.Payments.Add(newPayment);

            var totalPaid = payingInvoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
            if (totalPaid >= payingInvoice.TotalAmount)
            {
                payingInvoice.IsPaid = true;
            }

            await Db.SaveChangesAsync();
            showPaymentForm = false;
            await LoadData();
        }
        finally
        {
            isSaving = false;
        }
    }
}

